// לא Thread-Safe: race condition בבנאי
public class MyThing {
    static int count = 0;
    private int serialNum;
    public MyThing() { serialNum = count; count++; } // 2 threads יכולים לקרוא אותו count
}
// תיקון:
private static synchronized int getSN() {
    int serialNum = count;
    count++;
    return serialNum;
}

// Lock Starvation - שגוי
synchronized(done) {
    while (!done) { /* do stuff */ } // מחזיק מנעול לנצח!
}
// תיקון - כלל הברזל: החזק מנעולים לזמן הקצר ביותר
while (true) {
    synchronized(done) { if (done) break; }
    // do regular loop stuff...
}

ExecutorService pool = Executors.newFixedThreadPool(2);
Future<Integer> f = pool.submit(new Callable<Integer>() {
    public Integer call() throws InterruptedException {
        Thread.sleep(500);
        return 42;
    }
});
pool.shutdown();
System.out.println(f.get()); // blocks until result is ready -> 42

